import{_ as r}from"./chunks/logo.C4g6RddY.js";import{c as a,Q as t,j as i,m as o}from"./chunks/framework.BkjtU8k0.js";const s="/assets/demo1.CQxWqb4v.png",l="/assets/mp.CqDGcv-x.png",d="/assets/contact.B_TJ4ndC.jpg",_=JSON.parse('{"title":"文档导览","description":"","frontmatter":{},"headers":[],"relativePath":"guide/index.md","filePath":"guide/index.md","lastUpdated":1779097958000}'),n={name:"guide/index.md"};function h(c,e,f,g,p,u){return t(),i("div",null,[...e[0]||(e[0]=[o('<h1 id="文档导览" tabindex="-1">文档导览 <a class="header-anchor" href="#文档导览" aria-label="Permalink to &quot;文档导览&quot;">​</a></h1><div class="doc-kicker">Welcome To Flyfish Viewer</div><p class="doc-lead"> 欢迎来到 Flyfish Viewer 文档中心。 这里保留了项目最早对外介绍时那套核心表达，也补齐了面向成品交付的使用说明、集成方案与发布流程。你可以先快速浏览项目定位，再按需要进入 Vue3 集成、iframe 嵌入或本地打包章节。 </p><div class="doc-hero-logo"><img src="'+r+'" alt="Flyfish Viewer Logo"></div><h2 id="flyfish-viewer" tabindex="-1">Flyfish Viewer <a class="header-anchor" href="#flyfish-viewer" aria-label="Permalink to &quot;Flyfish Viewer&quot;">​</a></h2><blockquote><p>一款纯前端Serverless的全能文档预览器</p></blockquote><ul><li>✨ <strong>最新技术栈</strong>：基于 Vite + Vue2/3 + ts + 组合式 API</li><li>🚀 <strong>超高兼容性</strong>：内置 59 个扩展名映射，覆盖 Office、PDF、OFD、CAD、Markdown、代码/文本、图片和视频</li><li>⚡ <strong>超优质代码</strong>：完全异步组件加载，<strong>Web Worker</strong>，超高性能</li></ul><div class="doc-link-row"><a href="https://github.com/flyfish-dev/file-viewer" target="_blank" rel="noreferrer">GitHub 成品仓库</a><a href="https://dev.flyfish.group/shop" target="_blank" rel="noreferrer">源码自助开通</a><a href="/guide/quickstart">快速开始</a></div><h2 id="概述" tabindex="-1">概述 <a class="header-anchor" href="#概述" aria-label="Permalink to &quot;概述&quot;">​</a></h2><p>Flyfish Viewer 可以为您的应用快速集成文档预览能力。不同于市面上的文档预览方案，本项目对文档的所有解析和渲染全部都在浏览器端完成，不会给服务器造成任何额外的压力。与此同时，因其纯前端的特性，非常易于部署，可以部署在任何地方，如容器、服务器、甚至是手机、路由器等等。</p><p>查看<a href="/guide/quickstart">快速开始</a>了解详情。</p><h2 id="特性" tabindex="-1">特性 <a class="header-anchor" href="#特性" aria-label="Permalink to &quot;特性&quot;">​</a></h2><ul><li>📄 <strong>支持海量文件格式。</strong> 支持 <code>docx</code>、<code>pptx</code>、<code>xlsx</code>、<code>xls</code>、<code>pdf</code>、<code>ofd</code>、<code>dxf</code>、<code>markdown</code>、代码高亮、图片、视频等主流文件格式。</li><li>🌐 <strong>现代纯前端文档渲染方案。</strong> 纯前端文档预览解决方案，无需后端。</li><li>🛠 <strong>优质代码，优雅实现。</strong> 高质量的 TypeScript 代码，优雅的模块化实现。</li><li>🚀 <strong>持续使用最新架构。</strong> 基于最新 <strong>Vite</strong> 开发，并同时支持 <strong>Vue2</strong> 和 <strong>Vue3</strong>。</li><li>⚡ <strong>异步渲染和解析。</strong> 所有文件解析使用 <strong>Web Worker</strong> 异步处理，请纵享丝滑。</li><li>🧩 <strong>完全响应式数据构建。</strong> 使用完全的组合式 API 构建应用，高性能低占用。</li><li>🎨 <strong>支持完全的样式自定义。</strong> 解耦样式依赖，组件样式可以根据外部容器完全自适应。</li><li>🔌 <strong>更加灵活的扩展性。</strong> 支持自定义插件和钩子函数。</li><li>🎉 <strong>成品开放，持续更新</strong> 🎉🎉🎉</li></ul><h2 id="开发背景" tabindex="-1">开发背景 <a class="header-anchor" href="#开发背景" aria-label="Permalink to &quot;开发背景&quot;">​</a></h2><p><strong>Flyfish Viewer</strong>（原file-viewer）是飞鱼开源团队呕心沥血，历时两年打造的纯前端文档预览解决方案。该项目诞生于CSDN博文，旨在降低浏览器段文档预览的门槛，整合市面上成熟的文档预览技术而实现的一套解决方案。原文链接：<a href="https://blog.csdn.net/wybaby168/article/details/122842866" target="_blank" rel="noreferrer">https://blog.csdn.net/wybaby168/article/details/122842866</a></p><h2 id="示例" tabindex="-1">示例 <a class="header-anchor" href="#示例" aria-label="Permalink to &quot;示例&quot;">​</a></h2><p>可以查看 <a href="https://viewer.flyfish.dev" target="_blank" rel="noreferrer">Demo</a> 立即体验本组件。</p><p>公开 GitHub 仓库提供可直接下载使用的混淆压缩成品、示例文件和文档产物；如果需要源码、二开包或商业自助开通，请前往 <a href="https://dev.flyfish.group/shop" target="_blank" rel="noreferrer">https://dev.flyfish.group/shop</a>，付费 4.99 后自助开通。</p><div class="doc-shot"><img src="'+s+'" alt="Flyfish Viewer 旧版示例"><p class="doc-caption">这是项目早期文档中使用的展示图，今天再看，仍然能准确说明这套预览器的使用方式和页面气质。</p></div><h2 id="捐赠" tabindex="-1">捐赠 <a class="header-anchor" href="#捐赠" aria-label="Permalink to &quot;捐赠&quot;">​</a></h2><p>如果你觉得 Flyfish Viewer 对你有帮助，或者想要给我一些项目维护的支持，欢迎给我<a href="/donate">捐赠</a>。</p><blockquote><p>目前CSDN上售卖的资源因权限问题无法更新，请使用我们的官方渠道进行支持。</p></blockquote><h2 id="社区" tabindex="-1">社区 <a class="header-anchor" href="#社区" aria-label="Permalink to &quot;社区&quot;">​</a></h2><p>您可以关注我们的微信公众号，及时获取最新进展</p><img src="'+l+'" alt="微信公众号" style="width:400px;"><p>您也可以添加我们的客服微信<code>Yous_Gift</code>，咨询相关业务详情</p><img src="'+d+'" alt="客服微信" style="width:300px;"><h2 id="接下来去哪里" tabindex="-1">接下来去哪里 <a class="header-anchor" href="#接下来去哪里" aria-label="Permalink to &quot;接下来去哪里&quot;">​</a></h2><ol><li><a href="/guide/quickstart">快速开始</a></li><li><a href="/guide/quickstart-vue3">Vue3 集成</a></li><li><a href="/guide/iframe">Iframe 嵌入</a></li><li><a href="/guide/demo">Demo 说明</a></li><li><a href="/guide/development">本地开发与打包</a></li><li><a href="/guide/distribution">发布与成品分发</a></li></ol>',29)])])}const k=a(n,[["render",h]]);export{_ as __pageData,k as default};
